class Solution {
public:
    vector<set<int>> findAncestors(int n, vector<pair<int, int>>& edges) {
        vector<vector<int>> adj(n);
        vector<int> indegree(n, 0);

        for (auto& e : edges) {
            int x = e.first, y = e.second;
            adj[x].push_back(y);
            indegree[y]++;
        }

        queue<int> q;
        for (int i = 0; i < n; i++) {
            if (indegree[i] == 0)
                q.push(i);
        }

        vector<set<int>> ans(n);
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (int v : adj[u]) {
                ans[v].insert(u);
                for (int x : ans[u])
                    ans[v].insert(x);
                indegree[v]--;
                if (indegree[v] == 0)
                    q.push(v);
            }
        }

        return ans;
    }
};

