void push(Solution* sol, int x) {
    sol->queueArr[sol->rear++] = x;
}

int pop(Solution* sol) {
    return sol->queueArr[sol->front++];
}

int isEmpty(Solution* sol) {
    return sol->front == sol->rear;
}

// --- Ancestor management ---
int existsInAnc(Solution* sol, int node, int val) {
    for (int i = 0; i < sol->ancSize[node]; i++) {
        if (sol->ancestors[node][i] == val)
            return 1;
    }
    return 0;
}

void addAncestor(Solution* sol, int node, int val) {
    if (!existsInAnc(sol, node, val)) {
        sol->ancestors[node][sol->ancSize[node]++] = val;
    }
}

// --- Comparison function for sorting ---
int compareInt(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

void findAncestors(Solution* sol, int n, int m, int edges[][2]) {
    memset(sol->indegree, 0, sizeof(sol->indegree));
    memset(sol->adjSize, 0, sizeof(sol->adjSize));
    memset(sol->ancSize, 0, sizeof(sol->ancSize));
    sol->front = sol->rear = 0;

    for (int i = 0; i < m; i++) {
        int x = edges[i][0];
        int y = edges[i][1];
        sol->adj[x][sol->adjSize[x]++] = y;
        sol->indegree[y]++;
    }

    for (int i = 0; i < n; i++) {
        if (sol->indegree[i] == 0)
            push(sol, i);
    }

    while (!isEmpty(sol)) {
        int u = pop(sol);
        for (int i = 0; i < sol->adjSize[u]; i++) {
