class Solution {
    public List<Set<Integer>> findAncestors(int n, List<int[]> edges) {
        List<List<Integer>> adj = new ArrayList<>();
        int[] indegree = new int[n];

        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }

        for (int[] e : edges) {
            int x = e[0], y = e[1];
            adj.get(x).add(y);
            indegree[y]++;
        }

        Queue<Integer> q = new LinkedList<>();
        for (int i = 0; i < n; i++) {
            if (indegree[i] == 0)
                q.add(i);
        }

        List<Set<Integer>> ans = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            ans.add(new TreeSet<>()); // TreeSet keeps elements sorted
        }

        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v : adj.get(u)) {
                ans.get(v).add(u);
                ans.get(v).addAll(ans.get(u));
                indegree[v]--;
                if (indegree[v] == 0)
                    q.add(v);
            }
        }

        return ans;
    }
}

